3318 Instruction *InstCombinerImpl::visitSwitchInst(SwitchInst &SI) {
3319   Value *Cond = SI.getCondition();
3320   Value *Op0;
3321   ConstantInt *AddRHS;
3322   if (match(Cond, m_Add(m_Value(Op0), m_ConstantInt(AddRHS)))) {
3323     // Change 'switch (X+4) case 1:' into 'switch (X) case -3'.
3324     for (auto Case : SI.cases()) {
3325       Constant *NewCase = ConstantExpr::getSub(Case.getCaseValue(), AddRHS);
3326       assert(isa<ConstantInt>(NewCase) &&
3327              "Result of expression should be constant");
3328       Case.setValue(cast<ConstantInt>(NewCase));
3329     }
3330     return replaceOperand(SI, 0, Op0);
3331   }
3332 
3333   ConstantInt *SubLHS;
3334   if (match(Cond, m_Sub(m_ConstantInt(SubLHS), m_Value(Op0)))) {
3335     // Change 'switch (1-X) case 1:' into 'switch (X) case 0'.
3336     for (auto Case : SI.cases()) {
3337       Constant *NewCase = ConstantExpr::getSub(SubLHS, Case.getCaseValue());
3338       assert(isa<ConstantInt>(NewCase) &&
3339              "Result of expression should be constant");
3340       Case.setValue(cast<ConstantInt>(NewCase));
3341     }
3342     return replaceOperand(SI, 0, Op0);
3343   }
