2048 /// Compute the logical AND of the attributes of the caller and the
2049 /// callee.
2050 ///
2051 /// This function sets the caller's attribute to false if the callee's attribute
2052 /// is false.
2053 template<typename AttrClass>
2054 static void setAND(Function &Caller, const Function &Callee) {
2055   if (AttrClass::isSet(Caller, AttrClass::getKind()) &&
2056       !AttrClass::isSet(Callee, AttrClass::getKind()))
2057     AttrClass::set(Caller, AttrClass::getKind(), false);
