2111 /// If the inlined function defines the size of guard region
2112 /// on the stack, then ensure that the calling function defines a guard region
2113 /// that is no larger.
2114 static void
2115 adjustCallerStackProbeSize(Function &Caller, const Function &Callee) {
2116   Attribute CalleeAttr = Callee.getFnAttribute("stack-probe-size");
2117   if (CalleeAttr.isValid()) {
2118     Attribute CallerAttr = Caller.getFnAttribute("stack-probe-size");
2119     if (CallerAttr.isValid()) {
2120       uint64_t CallerStackProbeSize, CalleeStackProbeSize;
2121       CallerAttr.getValueAsString().getAsInteger(0, CallerStackProbeSize);
2122       CalleeAttr.getValueAsString().getAsInteger(0, CalleeStackProbeSize);
2123 
2124       if (CallerStackProbeSize > CalleeStackProbeSize) {
2125         Caller.addFnAttr(CalleeAttr);
2126       }
2127     } else {
2128       Caller.addFnAttr(CalleeAttr);
2129     }
2130   }
