2001 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
2002                                                FPClassTest DemandedMask,
2003                                                KnownFPClass &Known,
2004                                                unsigned Depth) {
2005   Use &U = I->getOperandUse(OpNo);
2006   Value *NewVal =
2007       SimplifyDemandedUseFPClass(U.get(), DemandedMask, Known, Depth, I);
2008   if (!NewVal)
2009     return false;
2010   if (Instruction *OpInst = dyn_cast<Instruction>(U))
2011     salvageDebugInfo(*OpInst);
2012 
2013   replaceUse(U, NewVal);
2014   return true;
2015 }
